constructor(public readonly socket: Socket) {
  this.socket.on('data', this.onData.bind(this));
  this.socket.on(TcpEventsMap.CONNECT, () => (this.isClosed = false));
  this.socket.on(TcpEventsMap.CLOSE, () => (this.isClosed = true));
  this.socket.on(TcpEventsMap.ERROR, () => (this.isClosed = true));
}

async multiForbidden(uids: number[]): Promise<void> {
  if (uids) {
    const pvs: string[] = []
    const ts: string[] = []
    const ps: string[] = []
    uids.forEach((uid) => {
      pvs.push(genAuthPVKey(uid))
      ts.push(genAuthTokenKey(uid))
      ps.push(genAuthPermKey(uid))
    })
    await this.redis.del(pvs)
    await this.redis.del(ts)
    await this.redis.del(ps)
  }
}

public exchangeKeyForValue(type: number, data: ParamData, args: any[]) {
  if (!args) {
    return null;
  }

  let index = 0;
  if (type === RABBIT_PARAM_TYPE) {
    index = 0;
  } else if (type === RABBIT_REQUEST_TYPE) {
    index = 1;
  } else if (type === RABBIT_HEADER_TYPE) {
    index = 2;
  }

  return data && !isObject(data) ? args[index]?.[data] : args[index];
}

resolveType(auth) {
  if (auth.type === WebhookAuthEnum.API_KEY) {
    return AuthApiKey;
  }
  if (auth.type === WebhookAuthEnum.BASIC) {
    return AuthBasic;
  }
  if (auth.type === WebhookAuthEnum.TOKEN) {
    return AuthToken;
  }
  if (auth.type === WebhookAuthEnum.OAUTH_2) {
    return AuthOAuth2;
  }
  return AuthNone;
}

error => {
  const { code } = error?.err ?? error ?? { code: 'CONN_ERR' };
  return throwError(() =>
    code === 'ECONNREFUSED' ||
    code === 'CONN_ERR' ||
    code === 'ENOTFOUND' ||
    code === 'CONNECTION_REFUSED' ||
    error.message.includes('Connection is closed.')
      ? new RequestTimeoutException('ECONNREFUSED')
      : new InternalServerErrorException(),
  );
}
